     7→#ifndef IREE_COMPILER_CODEGEN_LLVMCPU_TILESIZESELECTION_H_
     8→#define IREE_COMPILER_CODEGEN_LLVMCPU_TILESIZESELECTION_H_
     9→
    10→#include "iree/compiler/Codegen/Dialect/Codegen/IR/IREECodegenAttrs.h"
    11→#include "mlir/IR/BuiltinOps.h"
    12→
    13→namespace mlir::iree_compiler {
    14→
    15→using SizesAndScalableFlags =
    16→    std::pair<SmallVector<int64_t>, SmallVector<bool>>;
    17→
    18→/// Provides unified API to get access to all the tile size needed during the
    19→/// CPU lowering process, while abstracting the representation and verification
    20→/// details of such information in the IR.
    21→///
    22→/// We currently support the following scenarios:
    23→///   1. [[distribution]]
    24→///   2. [[distribution], [vector-common-parallel]]
    25→///   3. [[distribution], [vector-common-parallel], [vector-reduction]]
    26→///   4. [[distribution], [vector-common-parallel], [vector-reduction],
    27→///       [vector-inner-parallel]]
    28→///   5. [[distribution], [cache-parallel], [cache-reduction],
    29→///       [vector-parallel], [vector-reduction]]
    30→class TilingConfig {
    31→public:
    32→  TilingConfig(IREE::Codegen::LoweringConfigAttr lc);
    33→
    34→  /// Returns the number of tiling levels of the configuration.
    35→  unsigned getNumTilingLevels() {
    36→    return loweringConfig.getTilingLevels().size();
    37→  };
    38→
    39→  /// Returns the number of dimensions of the configuration. All the tiling
    40→  /// levels must have the same number of dimensions.
    41→  unsigned getNumDimensions() {
    42→    return getNumTilingLevels() > 0
    43→               ? loweringConfig.getTilingLevels()[0].getSizes().size()
    44→               : 0;
    45→  }
    46→
    47→  /// Returns the number of parallel dimensions to tile at vector level.
    48→  unsigned getNumVectorParallelTiles() {
    49→    unsigned parallelLevel = getVectorCommonParallelLevel();
    50→    if (parallelLevel <= getNumTilingLevels())
    51→      return 0;
    52→    return llvm::count_if(
    53→        loweringConfig.getTilingLevels()[parallelLevel].getSizes(),
    54→        [](int64_t tileSize) { return tileSize != 0; });
    55→  }
    56→
    57→  /// Returns the tiling level for cache parallel dimensions.
    58→  unsigned getDistributionLevel() { return getActualLevel(DistributionTiles); }
    59→
    60→  /// Returns the tiling level for cache parallel dimensions.
    61→  unsigned getCacheParallelLevel() {
    62→    return getActualLevel(CacheParallelTiles);
    63→  }
    64→
    65→  /// Returns the tiling level for cache reduction dimensions.
    66→  unsigned getCacheReductionLevel() {
    67→    return getActualLevel(CacheReductionTiles);
    68→  }
    69→
    70→  /// Returns the tiling level for vector common parallel dimensions.
    71→  unsigned getVectorCommonParallelLevel() {
    72→    return getActualLevel(VectorCommonParallelTiles);
    73→  }
    74→
    75→  /// Returns true if the tiling configuration has vector inner parallel
    76→  /// dimensions
    77→  bool hasVectorInnerParallelLevel() { return getNumTilingLevels() > 3; }
    78→
    79→  /// Returns the tiling level for vector inner parallel dimensions.
    80→  unsigned getVectorInnerParallelLevel() {
    81→    return getActualLevel(VectorInnerParallelTiles);
    82→  }
    83→
    84→  /// Returns the tiling level for vector parallel dimensions.
    85→  unsigned getVectorReductionLevel() {
    86→    return getActualLevel(VectorReductionTiles);
    87→  }
    88→
    89→  /// Returns all the tile sizes of all the levels of the configuration.
    90→  TileSizesListType getTileSizes() { return loweringConfig.getTileSizeVals(); }
    91→
    92→  /// Returns the distribution tile sizes of the configuration.
    93→  SmallVector<int64_t> getDistributionTileSizes() {
    94→    return getTileSizesForLevel(getActualLevel(DistributionTiles));
    95→  }
    96→
    97→  SmallVector<int64_t> getCacheReductionSizes() {
    98→    return getTileSizesForLevel(getCacheReductionLevel());
    99→  }
   100→
   101→  SizesAndScalableFlags getVectorCommonParallelSizes() {
   102→    return getVectorSizesForLevel(getVectorCommonParallelLevel());
   103→  }
   104→
   105→  SizesAndScalableFlags getVectorReductionSizes() {
   106→    return getVectorSizesForLevel(getVectorReductionLevel());
   107→  }
   108→
   109→  SizesAndScalableFlags getVectorInnerParallelSizes() {
   110→    return getVectorSizesForLevel(getVectorInnerParallelLevel());
   111→  }
   112→
   113→  /// Returns the tile sizes of all the vector dimensions, including parallel
   114→  /// and reduction dimensions.
   115→  SizesAndScalableFlags getVectorTileSizes();
   116→
   117→  /// Returns a new `LoweringConfigAttr`, with the tile sizes of vector
   118→  /// dimensions, set to `sizes`, and the corresponding scalability set to
   119→  /// `scalableFlags`.
   120→  IREE::Codegen::LoweringConfigAttr
   121→  getLoweringConfigWithNewVectorSizes(ArrayRef<int64_t> sizes,
   122→                                      ArrayRef<bool> scalableFlags = {});
   123→
   124→  /// Returns a list with the tiling levels that can be fused for this
   125→  /// configuration.
   126→  SmallVector<int64_t> getFusableLevels();
   127→
   128→  // TODO(dcaballe): Revisit if these features are ever used.
   129→  SmallVector<int64_t> getTileInterchangeSizes(unsigned level) {
   130→    return loweringConfig.getTileInterchangeVals(level);
   131→  }
   132→  SmallVector<int64_t> getNativeVectorSizes() {
   133→    return loweringConfig.getNativeVectorSizeVals();
   134→  }
   135→
   136→private:
   137→  SizesAndScalableFlags getVectorSizesForLevel(unsigned level) {
   138→    return std::make_pair(loweringConfig.getTileSizeVals(level),
   139→                          loweringConfig.getScalableTileFlagVals(level));
   140→  }
   141→
   142→  SmallVector<int64_t> getTileSizesForLevel(unsigned level) {
   143→    return loweringConfig.getTileSizeVals(level);
   144→  }
   145→
   146→  /// Returns the tiling level that contains the vector dim at `dimPos` (which
   147→  /// is an index into the result of `getVectorTileSizes()`).
   148→  std::optional<unsigned>
   149→  getTilingLevelForVectorDimPosition(unsigned dimPos) const;
   150→
   151→  /// Internal representation for all the supported tiling levels. All or just
   152→  /// a subset of them may be available in a valid configuration.
   153→  enum TilingLevel : unsigned {
   154→    DistributionTiles = 0,
   155→    CacheParallelTiles = 1,
   156→    CacheReductionTiles = 2,
   157→    VectorCommonParallelTiles = 3,
   158→    VectorReductionTiles = 4,
   159→    VectorInnerParallelTiles = 5,
   160→    MaxNumTileLevels = 6,
   161→    InvalidLevel = 7,
   162→  };
   163→
   164→  /// Returns the actual level in the configuration for this level of tiling.
   165→  unsigned getActualLevel(TilingLevel level);
   166→
   167→  /// Holds the lowering config that provides the configuration.
   168→  IREE::Codegen::LoweringConfigAttr loweringConfig;
   169→
   170→  /// Maps `TilingLevel`'s to the actual number of levels in this configuration.
   171→  std::array<unsigned, TilingLevel::MaxNumTileLevels>
   172→      tilingLevelToActualLevelMap;
   173→};
   174→
   175→} // namespace mlir::iree_compiler
   176→
   177→#endif // IREE_COMPILER_CODEGEN_LLVMCPU_TILESIZESELECTION_H_
   178→

