   287→def IREECodegen_LoweringConfigAttr :
   288→    AttrDef<IREECodegen_Dialect, "LoweringConfig", [
   289→      DeclareAttrInterfaceMethods<IREECodegen_LoweringConfigAttrInterface, [
   290→        "getWorkgroupTileSizes",
   291→        "getWorkgroupInterchange",
   292→        "getStaticTilingLevelSizes",
   293→        "getTilingLevelSizes",
   294→        "hasTilingLevel",
   295→        "hasWorkgroupTilingLevel",
   296→      ]>
   297→    ]> {
   298→  let mnemonic = "lowering_config";
   299→  let summary = [{drive lowering of an operation within dispatch region}];
   300→  let description = [{
   301→    Default implementation of a lowering configuration attribute. It includes
   302→    only tiling and optionally vectorization information. The interpretation of
