    46→// Shortened helper to compute the product of `values`.
    47→static int64_t prod(ArrayRef<int64_t> values) {
    48→  return ShapedType::getNumElements(values);
    49→}
    50→
    51→static int64_t calculateOperandsSharedMemoryUsedInBytes(
    52→    const GPUMMASchedule &schedule, int64_t lhsBitwidth, int64_t rhsBitwidth) {
    53→
    54→  int64_t tileM = schedule.mSize * prod(schedule.mTileSizes) *
    55→                  prod(schedule.mSubgroupCounts);
    56→  int64_t tileN = schedule.nSize * prod(schedule.nTileSizes) *
    57→                  prod(schedule.nSubgroupCounts);
    58→  int64_t tileK = schedule.kSize * prod(schedule.kTileSizes);
    59→  return (tileM * tileK * lhsBitwidth + tileN * tileK * rhsBitwidth) / 8;
    60→}
    61→
    62→static int64_t
    63→calculateResultSharedMemoryUsedInBytes(const GPUMMASchedule &schedule,
    64→                                       int64_t resultBitwidth) {
    65→
    66→  int64_t tileM = schedule.mSize * prod(schedule.mTileSizes) *
    67→                  prod(schedule.mSubgroupCounts);
    68→  int64_t tileN = schedule.nSize * prod(schedule.nTileSizes) *
    69→                  prod(schedule.nSubgroupCounts);
    70→  return (tileM * tileN * resultBitwidth) / 8;
    71→}
