    73→/// Check that a GPUMMASchedule fits alignment restrictions. To be aligned,
    74→/// the problem must be evenly divisible by the number of elements in the
    75→/// schedule for each dimension. If `mustBeAligned` is false, then the innermost
    76→/// problem dimension is allowed to be unaligned .
    77→static bool isScheduleAligned(const GPUMatmulShapeType &problem,
    78→                              const GPUMMASchedule &schedule,
    79→                              bool mustBeAligned) {
    80→  SmallVector<int64_t> alignedMSizes(problem.mSizes);
    81→  alignedMSizes.back() =
    82→      mustBeAligned ? problem.mSizes.back()
    83→                    : llvm::divideCeil(problem.mSizes.back(), schedule.mSize) *
    84→                          schedule.mSize;
    85→  SmallVector<int64_t> alignedNSizes(problem.nSizes);
    86→  alignedNSizes.back() =
    87→      mustBeAligned ? problem.nSizes.back()
    88→                    : llvm::divideCeil(problem.nSizes.back(), schedule.nSize) *
    89→                          schedule.nSize;
    90→  SmallVector<int64_t> alignedKSizes(problem.kSizes);
    91→  alignedKSizes.back() =
    92→      mustBeAligned ? problem.kSizes.back()
    93→                    : llvm::divideCeil(problem.kSizes.back(), schedule.kSize) *
    94→                          schedule.kSize;
    95→  // Returns the number of elements in the schedule for each dimension.
    96→  auto getScheduleSizes =
    97→      [&](int64_t size, SmallVector<int64_t> tileCount,
    98→          std::optional<SmallVector<int64_t>> subgroupCount) {
    99→        SmallVector<int64_t> sizes = llvm::map_to_vector(
   100→            llvm::seq<int64_t>(tileCount.size()), [&](int64_t i) {
   101→              return subgroupCount ? tileCount[i] * subgroupCount.value()[i]
   102→                                   : tileCount[i];
   103→            });
   104→        sizes.back() *= size;
   105→        return sizes;
   106→      };
   107→  // Checks whether the elements of `a` are evenly divisible by the
   108→  // corresponding elements of `b`.
   109→  auto areAligned = [](SmallVector<int64_t> a, SmallVector<int64_t> b) {
   110→    for (auto [aVal, bVal] : llvm::zip_equal(a, b)) {
   111→      if (aVal % bVal != 0) {
   112→        return false;
   113→      }
   114→    }
   115→    return true;
   116→  };
   117→  bool isValidM = areAligned(
   118→      alignedMSizes, getScheduleSizes(schedule.mSize, schedule.mTileSizes,
   119→                                      schedule.mSubgroupCounts));
   120→  bool isValidN = areAligned(
   121→      alignedNSizes, getScheduleSizes(schedule.nSize, schedule.nTileSizes,
   122→                                      schedule.nSubgroupCounts));
   123→  bool isValidK = areAligned(
   124→      alignedKSizes,
   125→      getScheduleSizes(schedule.kSize, schedule.kTileSizes, std::nullopt));
   126→  return isValidM && isValidN && isValidK;
   127→}
