   129→/// Returns whether or not a GPUMMASchedule is valid for the given problem.
   130→/// This checks that:
   131→///  - The problem is aligned to the schedule
   132→///  - the number of threads in the schedule workgroup can be distributed
   133→///    to a corresponding vector.transfer read in VectorDistribute.
   134→static bool isValidMMASchedule(const GPUMatmulShapeType &problem,
   135→                               const GPUMMASchedule &schedule,
   136→                               bool mustBeAligned, int64_t subgroupSize,
   137→                               bool transposedLhs, bool transposedRhs) {
   138→  bool isAligned = isScheduleAligned(problem, schedule, mustBeAligned);
   139→
   140→  // Constraint to ensure wgTileSize is distributable by wgSize.
   141→  // such that we can distribute to it's corresponding vector.transfer_read.
   142→  const int64_t kMaxVectorLoadBitWidth = 128;
   143→  int64_t elemsPerThread =
   144→      kMaxVectorLoadBitWidth / problem.bType.getIntOrFloatBitWidth();
   145→  int64_t wgThreads = subgroupSize * prod(schedule.mSubgroupCounts) *
   146→                      prod(schedule.nSubgroupCounts);
   147→  int64_t mWgSize = schedule.mSize * prod(schedule.mTileSizes) *
   148→                    prod(schedule.mSubgroupCounts);
   149→  int64_t nWgSize = schedule.nSize * prod(schedule.nTileSizes) *
   150→                    prod(schedule.nSubgroupCounts);
   151→  int64_t kWgSize = schedule.kSize * prod(schedule.kTileSizes);
   152→  int64_t innerLhsDimSize = transposedLhs ? mWgSize : kWgSize;
   153→  int64_t innerRhsDimSize = transposedRhs ? kWgSize : nWgSize;
   154→
   155→  bool isDistributableLhs =
   156→      (innerLhsDimSize / elemsPerThread) % wgThreads == 0 ||
   157→      wgThreads % (innerLhsDimSize / elemsPerThread) == 0;
   158→  bool isDistributableRhs =
   159→      (innerRhsDimSize / elemsPerThread) % wgThreads == 0 ||
   160→      wgThreads % (innerRhsDimSize / elemsPerThread) == 0;
   161→
   162→  return isAligned && isDistributableLhs && isDistributableRhs;
   163→}
