   165→/// Tries to fit the schedule into shared memory by decrementing the size of the
   166→/// schedule dimensions from outermost to innermost until a valid schedule is
   167→/// found. The schedule sizes are reduced in the order of mTileSizes,
   168→/// nTileSizes, kTileSizes, mSubgroupCounts, nSubgroupCounts.
   169→static FailureOr<GPUMMASchedule> fitScheduleInSharedMemory(
   170→    GPUMatmulShapeType intrinsic, GPUMMASchedule schedule,
   171→    llvm::function_ref<bool(const GPUMMASchedule &schedule)> isScheduleValid) {
   172→
   173→  while (!isScheduleValid(schedule)) {
   174→    LLVM_DEBUG({
   175→      llvm::dbgs() << "Chosen schedule is invalid:\n";
   176→      llvm::dbgs() << schedule << "\n";
   177→      llvm::dbgs() << "Shrinking schedule...\n";
   178→    });
   179→
   180→    auto decrementIfPossible =
   181→        [](SmallVector<int64_t> &sizes) -> LogicalResult {
   182→      for (int64_t &size : sizes) {
   183→        if (size <= 1)
   184→          continue;
   185→        --size;
   186→        return success();
   187→      }
   188→      return failure();
   189→    };
   190→
   191→    // Attempt to shrink the schedule along one of the dimensions.
   192→    // TODO: A better solution should probably factor problem.mSize /
   193→    // (mSubgroupCount * mTileCount * mSize) and then pop off the smallest
   194→    // factors one at a time, preferably trying to keep the tile "generally
   195→    // square."
   196→    if (succeeded(decrementIfPossible(schedule.mTileSizes))) {
   197→      continue;
   198→    }
   199→    if (succeeded(decrementIfPossible(schedule.nTileSizes))) {
   200→      continue;
   201→    }
   202→    if (succeeded(decrementIfPossible(schedule.kTileSizes))) {
   203→      continue;
   204→    }
   205→    if (succeeded(decrementIfPossible(schedule.mSubgroupCounts))) {
   206→      continue;
   207→    }
   208→    if (succeeded(decrementIfPossible(schedule.nSubgroupCounts))) {
   209→      continue;
   210→    }
   211→
   212→    // If no dimension can be shrunk, give up.
   213→    return failure();
   214→  }
   215→
   216→  LLVM_DEBUG({
   217→    llvm::dbgs() << "Chosen schedule is valid:\n";
   218→    llvm::dbgs() << schedule << "\n";
   219→  });
   220→
   221→  return schedule;
   222→}
